// Generated by generate.ts — hidden adversarial suite for array-utils.
// Run via `npx tsx __audit__/arrayUtils.hidden.ts` inside the scratch project.
import { take, drop, last, first, partition } from '../src/arrayUtils'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("take basic", take([1,2,3,4,5], 3), [1,2,3])
await check("take more than length", take([1,2], 10), [1,2])
await check("take 0", take([1,2,3], 0), [])
await check("drop basic", drop([1,2,3,4,5], 2), [3,4,5])
await check("drop all", drop([1,2,3], 10), [])
await check("drop 0", drop([1,2,3], 0), [1,2,3])
await check("last basic", last([1,2,3]), 3)
await check("last empty", last([]), undefined)
await check("first basic", first([1,2,3]), 1)
await check("first empty", first([]), undefined)
await check("partition evens/odds", partition([1,2,3,4,5], n=>n%2===0), [[2,4],[1,3,5]])
await check("partition empty", partition([], ()=>true), [[],[]])
await check("partition all true", partition([1,2,3], ()=>true), [[1,2,3],[]])
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
